#!/usr/bin/env bash
set -euo pipefail

INSTALL_ROOT="${HOME}/.local/share/aster-browser-portable"
APP_DIR="${INSTALL_ROOT}/app"
RUNTIME_DIR="${INSTALL_ROOT}/runtime"
VENV_DIR="${RUNTIME_DIR}/venv"
LAUNCHER="${INSTALL_ROOT}/aster-launch.sh"
DESKTOP_FILE="${HOME}/.local/share/applications/org.aster.Browser.desktop"
ICON_DIR="${HOME}/.local/share/icons/hicolor/scalable/apps"
ICON_FILE="${ICON_DIR}/org.aster.Browser.svg"
TMP_DIR="$(mktemp -d)"
NO_RUN=0
EXTRACT_ONLY=0

cleanup() { rm -rf "$TMP_DIR"; }
trap cleanup EXIT

msg() { printf '[Aster Installer] %s
' "$*"; }
die() { printf '[Aster Installer] %s
' "$*" >&2; exit 1; }

while [[ $# -gt 0 ]]; do
  case "$1" in
    --no-run) NO_RUN=1 ;;
    --extract-only) EXTRACT_ONLY=1; NO_RUN=1 ;;
    *) die "Unknown option: $1" ;;
  esac
  shift
done

PYTHON_BIN="python3"
if ! command -v "$PYTHON_BIN" >/dev/null 2>&1; then
  PYTHON_BIN="python"
fi
command -v "$PYTHON_BIN" >/dev/null 2>&1 || die "python3 or python is required"
command -v base64 >/dev/null 2>&1 || die "base64 is required"
command -v tar >/dev/null 2>&1 || die "tar is required"

extract_payload() {
  local target_root="$1"
  mkdir -p "$target_root"
  cat > "$TMP_DIR/payload.b64" <<'PAYLOAD'

PAYLOAD
  base64 -d "$TMP_DIR/payload.b64" > "$TMP_DIR/payload.tar.gz"
  rm -rf "$APP_DIR"
  mkdir -p "$INSTALL_ROOT"
  tar -xzf "$TMP_DIR/payload.tar.gz" -C "$INSTALL_ROOT"
}

create_launcher() {
  mkdir -p "${INSTALL_ROOT}"
  cat > "$LAUNCHER" <<EOF
#!/usr/bin/env bash
set -euo pipefail
cd "$APP_DIR"
exec "$VENV_DIR/bin/python" "$APP_DIR/run_aster.py" "\$@"
EOF
  chmod 755 "$LAUNCHER"
}

create_desktop_entry() {
  mkdir -p "$(dirname "$DESKTOP_FILE")" "$ICON_DIR"
  if [[ -f "$APP_DIR/packaging/linux/aster.svg" ]]; then
    cp "$APP_DIR/packaging/linux/aster.svg" "$ICON_FILE"
  fi
  cat > "$DESKTOP_FILE" <<EOF
[Desktop Entry]
Type=Application
Name=Aster Browser
Comment=Linux-first browser shell with fullscreen video handling and touchpad gestures
Exec=$LAUNCHER %U
Icon=org.aster.Browser
Categories=Network;WebBrowser;
Terminal=false
StartupNotify=true
MimeType=text/html;text/xml;application/xhtml+xml;x-scheme-handler/http;x-scheme-handler/https;
EOF
}

install_runtime() {
  mkdir -p "$RUNTIME_DIR"
  if [[ ! -x "$VENV_DIR/bin/python" ]]; then
    msg "Creating private Python runtime"
    "$PYTHON_BIN" -m venv "$VENV_DIR"
  fi
  msg "Installing Python dependencies (first run can take a bit)"
  "$VENV_DIR/bin/pip" install --upgrade pip >/dev/null
  "$VENV_DIR/bin/pip" install -r "$APP_DIR/requirements-lock.txt"
}

msg "Bundled app extracted to $APP_DIR"
extract_payload "$INSTALL_ROOT"
create_launcher
create_desktop_entry
if [[ "$EXTRACT_ONLY" -eq 1 ]]; then
  msg "Extraction finished. Launcher: $LAUNCHER"
  exit 0
fi
install_runtime
msg "Launcher created at $LAUNCHER"
msg "Desktop entry created at $DESKTOP_FILE"
if [[ "$NO_RUN" -eq 0 ]]; then
  msg "Starting Aster Browser..."
  exec "$LAUNCHER"
fi
